<template><div class="page"><header class="page-head"><div><h1>Bibliotheque</h1><p>Catalogue Plex, demandes en cours et suivi des versions.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><section class="metric-grid compact-metrics"><article v-for="entry in metrics" :key="entry.label" class="metric-card"><span>{{ entry.label }}</span><strong>{{ entry.value }}</strong></article></section><div class="toolbar wrap"><input v-model="query" class="search" type="search" placeholder="Rechercher" @input="scheduleLoad"><div class="segmented"><button :class="{active:type===''}" @click="setType('')">Tout</button><button :class="{active:type==='movie'}" @click="setType('movie')">Films</button><button :class="{active:type==='show'}" @click="setType('show')">Series</button></div><select v-model="vf"><option value="">Toutes les versions</option><option value="vf">VF</option><option value="vo">VO</option><option value="unchecked">Non analysee</option></select><div class="segmented"><button :class="{active:view==='grid'}" title="Grille" @click="setView('grid')"><Grid2X2/></button><button :class="{active:view==='list'}" title="Liste" @click="setView('list')"><List/></button></div></div><p v-if="error" class="notice error-text">{{ error }}</p><section :class="view==='grid'?'media-grid':'panel media-list'"><button v-for="item in filtered" :key="`${item._kind}-${item.id}`" class="media-card interactive" :class="{list:view==='list'}" @click="selected=item"><div class="poster-shell"><img v-if="item.poster_url" :src="item.poster_url" alt="" loading="lazy"><div v-else class="poster-fallback"><Film/></div><span class="language-tag" :class="item.has_vf===true?'vf':item.has_vf===false?'vo':'unknown'">{{ item.has_vf===true?'VF':item.has_vf===false?'VO':'?' }}</span></div><div><strong>{{ item.title }}</strong><span>{{ item.media_type==='show'?'Serie':'Film' }}<template v-if="item.year"> · {{ item.year }}</template></span><small v-if="item._kind==='request'">{{ requestLabel(item.status) }}<template v-if="item.overview"> — {{ item.overview }}</template></small><small v-else-if="item.overview">{{ item.overview }}</small></div></button></section><p v-if="!loading&&!filtered.length" class="empty">Aucun media.</p><MediaDetailDrawer v-if="selected" :item="selected" :mode="selected._kind==='request'?'request':'library'" @close="selected=null" @updated="load"/></div></template>
<script setup>import { computed,onMounted,ref } from 'vue';import { Film,Grid2X2,List,RefreshCw } from '@lucide/vue';import { api } from '@/api';import MediaDetailDrawer from '@/components/MediaDetailDrawer.vue';const items=ref([]),rawMetrics=ref({}),query=ref(''),type=ref(''),vf=ref(''),view=ref(localStorage.getItem('library.view')||'grid'),selected=ref(null),loading=ref(false),error=ref('');let timer;const filtered=computed(()=>items.value.filter(item=>vf.value==='vf'?item.has_vf===true:vf.value==='vo'?item.has_vf===false:vf.value==='unchecked'?item.has_vf==null:true));const libraryItems=computed(()=>items.value.filter(x=>x._kind==='library'));const metrics=computed(()=>[{label:'Dans Plex',value:rawMetrics.value.total??libraryItems.value.length},{label:'En cours',value:items.value.length-libraryItems.value.length},{label:'Films',value:rawMetrics.value.by_type?.movie??libraryItems.value.filter(x=>x.media_type==='movie').length},{label:'Avec VF',value:rawMetrics.value.vf?.complete??libraryItems.value.filter(x=>x.has_vf===true).length}]);function setType(value){type.value=value;load()}function setView(value){view.value=value;localStorage.setItem('library.view',value)}function scheduleLoad(){clearTimeout(timer);timer=setTimeout(load,250)}function requestLabel(status){return ({pending_approval:'A approuver',pending:'En attente',sent_to_arr:'Transmise',failed:'Echec'})[status]||status}async function load(){loading.value=true;error.value='';const p=new URLSearchParams();if(query.value.trim())p.set('query',query.value.trim());if(type.value)p.set('media_type',type.value);try{const [library,requests,stats]=await Promise.all([api(`/api/library?${p}`),api(`/api/requests${query.value.trim()?`?query=${encodeURIComponent(query.value.trim())}`:''}`),api(`/api/library-metrics${type.value?`?media_type=${type.value}`:''}`).catch(()=>({}))]);const pending=requests.filter(x=>x.status!=='available'&&!x.library_item_id&&(!type.value||x.media_type===type.value)).map(x=>({...x,_kind:'request'}));items.value=[...library.map(x=>({...x,_kind:'library'})),...pending];rawMetrics.value=stats}catch(e){error.value=e.message}finally{loading.value=false}}onMounted(load);</script>
